sys_script_include.script:
var SearchPulseSignalAPI = Class.create();
SearchPulseSignalAPI.prototype = Object.extendsObject(AbstractAjaxProcessor, {
    type: 'SearchPulseSignalAPI',

    /**
     * captureSignal(session, signal, article)
     * Called via GlideAjax from SearchPulseTracker UI Script.
     *
     * GlideAjax parameters:
     *   sysparm_session  - session_id string (from x_searchpulse_session)
     *   sysparm_signal   - one of: summary_up, summary_down, scroll, click, return, reformulate
     *   sysparm_article  - (optional) sys_id of kb_knowledge for 'click' signal
     *
     * Returns JSON: { status:'ok'|'error', signal:'...', updated:true|false }
     */
    captureSignal: function() {
        var sessionId = this.getParameter('sysparm_session') || '';
        var signal    = this.getParameter('sysparm_signal')  || '';
        var article   = this.getParameter('sysparm_article') || '';

        if (!sessionId || !signal) {
            return JSON.stringify({ status: 'error', message: 'Missing session or signal parameter' });
        }

        var gr = new GlideRecord('x_searchpulse_session');
        gr.addQuery('session_id', sessionId);
        gr.setLimit(1);
        gr.query();

        if (!gr.next()) {
            return JSON.stringify({ status: 'error', message: 'Session not found: ' + sessionId });
        }

        var updated = false;

        switch (signal) {
            case 'summary_up':
                if (gr.getValue('summary_feedback') === 'none') {
                    gr.setValue('summary_feedback', 'up');
                    updated = true;
                }
                break;

            case 'summary_down':
                if (gr.getValue('summary_feedback') === 'none') {
                    gr.setValue('summary_feedback', 'down');
                    updated = true;
                }
                break;

            case 'scroll':
                if (gr.getValue('scrolled_summary') !== '1') {
                    gr.setValue('scrolled_summary', true);
                    updated = true;
                }
                break;

            case 'click':
                if (article && gr.getValue('result_clicked') !== '1') {
                    var kbGR = new GlideRecord('kb_knowledge');
                    if (kbGR.get(article)) {
                        gr.setValue('clicked_article', article);
                        gr.setValue('result_clicked', true);
                        updated = true;
                    }
                }
                break;

            case 'return':
                if (gr.getValue('came_back') !== '1') {
                    gr.setValue('came_back', true);
                    updated = true;
                }
                break;

            case 'reformulate':
                if (gr.getValue('reformulated') !== '1') {
                    gr.setValue('reformulated', true);
                    updated = true;
                }
                break;

            default:
                return JSON.stringify({ status: 'error', message: 'Unknown signal: ' + signal });
        }

        if (updated) {
            gr.update();
        }

        gs.log('SearchPulseSignalAPI: session=' + sessionId + ' signal=' + signal + ' updated=' + updated, 'SearchPulse');
        return JSON.stringify({ status: 'ok', signal: signal, updated: updated });
    },

    /**
     * createSession - creates a new x_searchpulse_session record.
     * Parameters: sysparm_session_id, sysparm_query, sysparm_user
     */
    createSession: function() {
        var sessionId = this.getParameter('sysparm_session_id') ||
                        gs.generateGUID().replace(/-/g, '').substring(0, 32);
        var query     = this.getParameter('sysparm_query') || '';
        var userId    = this.getParameter('sysparm_user')  || '';

        if (!query) {
            return JSON.stringify({ status: 'error', message: 'query is required' });
        }

        /* idempotent - return existing if already created */
        var chk = new GlideRecord('x_searchpulse_session');
        chk.addQuery('session_id', sessionId);
        chk.setLimit(1);
        chk.query();
        if (chk.next()) {
            return JSON.stringify({ status: 'ok', session_id: sessionId, sys_id: chk.getUniqueValue(), existed: true });
        }

        var gr = new GlideRecord('x_searchpulse_session');
        gr.initialize();
        gr.setValue('session_id',       sessionId);
        gr.setValue('query',            query);
        gr.setValue('summary_feedback', 'none');
        gr.setValue('scrolled_summary', false);
        gr.setValue('result_clicked',   false);
        gr.setValue('came_back',        false);
        gr.setValue('reformulated',     false);
        gr.setValue('outcome',          'B');
        gr.setValue('timestamp',        new GlideDateTime().getValue());

        if (userId) {
            var uGR = new GlideRecord('sys_user');
            if (uGR.get(userId)) { gr.setValue('user', userId); }
        }

        var sysId = gr.insert();
        gs.log('SearchPulseSignalAPI: created session id=' + sessionId + ' query=' + query, 'SearchPulse');
        return JSON.stringify({ status: 'ok', session_id: sessionId, sys_id: sysId, existed: false });
    }
});

var SearchPulseSessionClassifier = Class.create();
SearchPulseSessionClassifier.prototype = {
    type: 'SearchPulseSessionClassifier',

    /**
     * classify(sessionGR)
     * Classifies a single session GlideRecord and persists outcome field.
     *
     * Outcome rules (per spec):
     *   A  summary_feedback=up AND result_clicked=false
     *   C  result_clicked=true AND came_back=false
     *   D  result_clicked=true AND came_back=true AND reformulated=false
     *   E  reformulated=true
     *   F  summary_feedback=down
     *   B  (default - ambiguous)
     *
     * @param  sessionGR  GlideRecord on x_searchpulse_session
     * @return outcome letter string
     */
    classify: function(sessionGR) {
        if (!sessionGR || !sessionGR.isValidRecord()) {
            gs.logWarning('SearchPulseSessionClassifier: invalid record', 'SearchPulse');
            return 'B';
        }

        var outcome = this._determineOutcome(sessionGR);
        sessionGR.setValue('outcome', outcome);
        sessionGR.update();

        gs.log('SearchPulseSessionClassifier: ' + sessionGR.getValue('session_id') +
               ' classified => outcome ' + outcome, 'SearchPulse');
        return outcome;
    },

    /** classifyById(sessionId) - convenience method by session_id string */
    classifyById: function(sessionId) {
        var gr = new GlideRecord('x_searchpulse_session');
        gr.addQuery('session_id', sessionId);
        gr.setLimit(1);
        gr.query();
        if (!gr.next()) {
            gs.logWarning('SearchPulseSessionClassifier: session not found: ' + sessionId, 'SearchPulse');
            return 'B';
        }
        return this.classify(gr);
    },

    /**
     * classifyPending()
     * Bulk-classifies sessions still at outcome=B, older than 30 minutes.
     * Called nightly by the Reputation Calculator scheduled job.
     * @return count of sessions classified
     */
    classifyPending: function() {
        var count  = 0;
        var cutoff = new GlideDateTime();
        cutoff.addSeconds(-1800);

        var gr = new GlideRecord('x_searchpulse_session');
        gr.addQuery('outcome', 'B');
        gr.addQuery('timestamp', '<=', cutoff.getValue());
        gr.query();

        while (gr.next()) {
            this.classify(gr);
            count++;
        }

        gs.log('SearchPulseSessionClassifier: classified ' + count + ' pending sessions', 'SearchPulse');
        return count;
    },

    _determineOutcome: function(s) {
        var fb          = s.getValue('summary_feedback');
        var clicked     = (s.getValue('result_clicked') === '1' || s.getValue('result_clicked') === true);
        var cameBack    = (s.getValue('came_back')      === '1' || s.getValue('came_back')      === true);
        var reformulated = (s.getValue('reformulated')  === '1' || s.getValue('reformulated')   === true);

        /* Priority order: most disruptive first */
        if (reformulated)                          { return 'E'; }
        if (fb === 'down')                         { return 'F'; }
        if (clicked && cameBack && !reformulated)  { return 'D'; }
        if (clicked && !cameBack)                  { return 'C'; }
        if (fb === 'up' && !clicked)               { return 'A'; }
        return 'B';
    }
};

var SearchPulseConfidence = Class.create();
SearchPulseConfidence.prototype = {
    type: 'SearchPulseConfidence',

    /**
     * calculateConfidence(articleList)
     *
     * Confidence score = average reputation_score of cited articles.
     * Score bands:
     *   >= 70  -> High   (green)
     *   45-69  -> Medium (amber)
     *   < 45   -> Low    (red)
     *
     * @param  articleList  Array of kb_knowledge sys_id strings
     * @return { score, label, color, cssClass, description }
     */
    calculateConfidence: function(articleList) {
        if (!articleList || articleList.length === 0) {
            return this._result(50, 'No source articles provided - defaulting to Medium.');
        }

        var total = 0, count = 0;
        for (var i = 0; i < articleList.length; i++) {
            if (articleList[i]) {
                total += this._getReputationScore(articleList[i]);
                count++;
            }
        }

        var avg = (count > 0) ? Math.round(total / count) : 50;
        return this._result(avg, 'Averaged from ' + count + ' source article(s).');
    },

    /**
     * calculateConfidenceForSession(sessionSysId)
     * Reads x_searchpulse_summary_sources for the session, then delegates.
     */
    calculateConfidenceForSession: function(sessionSysId) {
        if (!sessionSysId) { return this._result(50, 'No session provided.'); }

        var ids = [];
        var gr  = new GlideRecord('x_searchpulse_summary_sources');
        gr.addQuery('session', sessionSysId);
        gr.query();
        while (gr.next()) {
            var artId = gr.getValue('article');
            if (artId) { ids.push(artId); }
        }

        return this.calculateConfidence(ids);
    },

    _getReputationScore: function(articleSysId) {
        var gr = new GlideRecord('x_searchpulse_article_reputation');
        gr.addQuery('article', articleSysId);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) {
            var s = parseInt(gr.getValue('reputation_score'), 10);
            return isNaN(s) ? 50 : s;
        }
        return 50; /* default for articles with no reputation record yet */
    },

    _result: function(score, description) {
        var label, color, cssClass;
        if      (score >= 70) { label = 'High';   color = 'green'; cssClass = 'sp-confidence-high';   }
        else if (score >= 45) { label = 'Medium'; color = 'amber'; cssClass = 'sp-confidence-medium'; }
        else                  { label = 'Low';    color = 'red';   cssClass = 'sp-confidence-low';    }
        return { score: score, label: label, color: color, cssClass: cssClass, description: description };
    }
};

var SearchPulseBadgeEngine = Class.create();
SearchPulseBadgeEngine.prototype = {
    type: 'SearchPulseBadgeEngine',

    BADGE_FREQUENTLY_HELPFUL: 'Frequently Helpful',
    BADGE_UPDATED_RECENTLY:   'Updated Recently',
    BADGE_MAY_BE_OUTDATED:    'May Be Outdated',

    /**
     * getBadge(articleSysId)
     *
     * Badge rules (per spec):
     *   reputation >= 75                                     -> Frequently Helpful (green)
     *   updated within 30 days AND reputation >= 50          -> Updated Recently   (blue)
     *   reputation < 50 AND article updated > 180 days ago   -> May Be Outdated    (amber)
     *   else                                                 -> no badge
     *
     * @param  articleSysId  sys_id of kb_knowledge record
     * @return { badge, color, icon, show }
     */
    getBadge: function(articleSysId) {
        if (!articleSysId) { return this._noBadge(); }

        var score     = this._getScore(articleSysId);
        var daysSince = this._daysSinceUpdate(articleSysId);

        if (score >= 75) {
            return this._makeBadge(this.BADGE_FREQUENTLY_HELPFUL, 'green', 'fa-check-circle');
        }
        if (daysSince !== null && daysSince <= 30 && score >= 50) {
            return this._makeBadge(this.BADGE_UPDATED_RECENTLY, 'blue', 'fa-refresh');
        }
        if (score < 50 && daysSince !== null && daysSince > 180) {
            return this._makeBadge(this.BADGE_MAY_BE_OUTDATED, 'amber', 'fa-exclamation-triangle');
        }
        return this._noBadge();
    },

    /**
     * getBadgesForList(sysIds)
     * Batch variant - returns { sysId: badgeObject } map.
     * Single DB queries per table for efficiency.
     */
    getBadgesForList: function(sysIds) {
        if (!sysIds || sysIds.length === 0) { return {}; }

        var repMap    = this._bulkReputation(sysIds);
        var updateMap = this._bulkUpdateDays(sysIds);
        var result    = {};

        for (var i = 0; i < sysIds.length; i++) {
            var sid   = sysIds[i];
            var score = (repMap[sid] !== undefined) ? repMap[sid] : 50;
            var days  = (updateMap[sid] !== undefined) ? updateMap[sid] : null;

            if (score >= 75) {
                result[sid] = this._makeBadge(this.BADGE_FREQUENTLY_HELPFUL, 'green', 'fa-check-circle');
            } else if (days !== null && days <= 30 && score >= 50) {
                result[sid] = this._makeBadge(this.BADGE_UPDATED_RECENTLY, 'blue', 'fa-refresh');
            } else if (score < 50 && days !== null && days > 180) {
                result[sid] = this._makeBadge(this.BADGE_MAY_BE_OUTDATED, 'amber', 'fa-exclamation-triangle');
            } else {
                result[sid] = this._noBadge();
            }
        }
        return result;
    },

    _getScore: function(articleSysId) {
        var gr = new GlideRecord('x_searchpulse_article_reputation');
        gr.addQuery('article', articleSysId);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) {
            var s = parseInt(gr.getValue('reputation_score'), 10);
            return isNaN(s) ? 50 : s;
        }
        return 50;
    },

    _daysSinceUpdate: function(articleSysId) {
        var gr = new GlideRecord('kb_knowledge');
        if (!gr.get(articleSysId)) { return null; }
        var upd = gr.getValue('sys_updated_on');
        if (!upd) { return null; }
        var diff = GlideDateTime.subtract(new GlideDateTime(upd), new GlideDateTime());
        return Math.abs(Math.floor(diff.getDayPart()));
    },

    _bulkReputation: function(sysIds) {
        var map = {};
        var gr  = new GlideRecord('x_searchpulse_article_reputation');
        gr.addQuery('article', 'IN', sysIds.join(','));
        gr.query();
        while (gr.next()) {
            var s = parseInt(gr.getValue('reputation_score'), 10);
            map[gr.getValue('article')] = isNaN(s) ? 50 : s;
        }
        return map;
    },

    _bulkUpdateDays: function(sysIds) {
        var map = {}, now = new GlideDateTime();
        var gr  = new GlideRecord('kb_knowledge');
        gr.addQuery('sys_id', 'IN', sysIds.join(','));
        gr.query();
        while (gr.next()) {
            var upd = gr.getValue('sys_updated_on');
            if (upd) {
                var diff = GlideDateTime.subtract(new GlideDateTime(upd), now);
                map[gr.getUniqueValue()] = Math.abs(Math.floor(diff.getDayPart()));
            } else {
                map[gr.getUniqueValue()] = null;
            }
        }
        return map;
    },

    _makeBadge: function(badge, color, icon) {
        return { badge: badge, color: color, icon: icon, show: true };
    },

    _noBadge: function() {
        return { badge: '', color: null, icon: null, show: false };
    }
};

sys_trigger.script:
/**
 * SearchPulse Reputation Calculator
 * Scheduled: Daily at 02:00
 *
 * Algorithm:
 *  1. Classify any unclassified sessions (outcome=B, older than 30 min).
 *  2. Loop through all distinct KB articles referenced via clicked_article.
 *  3. For each article, sum outcome weights from the last 24h of sessions:
 *       Outcome A  +3   (Summary satisfied)
 *       Outcome C  +1   (Drilled down success)
 *       Outcome D  -5   (Result failed)
 *       Outcome E  -10  (Full search failure)
 *       Outcome F  -15  (Summary rejected)
 *       Outcome B   0   (Ambiguous - no change)
 *  4. new_score = clamp(current_score + delta, 0, 100)
 *  5. Upsert x_searchpulse_article_reputation record.
 *
 * NOTE: Score starts at 50 for any article with no reputation record yet.
 */

gs.log('SearchPulse Reputation Calculator: START', 'SearchPulse');
var JOB_START = new GlideDateTime();
var WEIGHTS   = { 'A': 3, 'B': 0, 'C': 1, 'D': -5, 'E': -10, 'F': -15 };

/* Step 1: Classify pending sessions */
try {
    var classifier    = new x_searchpulse.SearchPulseSessionClassifier();
    var preClassified = classifier.classifyPending();
    gs.log('SearchPulse Reputation Calculator: pre-classified ' + preClassified + ' sessions', 'SearchPulse');
} catch (ce) {
    gs.logError('SearchPulse Reputation Calculator: session classification error - ' + ce.message, 'SearchPulse');
}

/* Step 2: Collect distinct articles */
var articleIds = _getDistinctArticles();
gs.log('SearchPulse Reputation Calculator: ' + articleIds.length + ' articles to score', 'SearchPulse');

/* Step 3-5: Score each article */
var scored = 0, errors = 0;
for (var i = 0; i < articleIds.length; i++) {
    try {
        if (_scoreArticle(articleIds[i])) { scored++; }
    } catch (ae) {
        errors++;
        gs.logError('SearchPulse Reputation Calculator: error on article=' + articleIds[i] + ' - ' + ae.message, 'SearchPulse');
    }
}

var elapsed = Math.abs(GlideDateTime.subtract(JOB_START, new GlideDateTime()).getNumericValue()) / 1000;
gs.log('SearchPulse Reputation Calculator: DONE scored=' + scored + ' errors=' + errors + ' elapsed=' + elapsed + 's', 'SearchPulse');

/* ---- helper functions ---- */

function _getDistinctArticles() {
    var ids  = [], seen = {};
    var gr   = new GlideRecord('x_searchpulse_session');
    gr.addNotNullQuery('clicked_article');
    gr.query();
    while (gr.next()) {
        var id = gr.getValue('clicked_article');
        if (id && !seen[id]) { seen[id] = true; ids.push(id); }
    }
    return ids;
}

function _scoreArticle(articleSysId) {
    /* Fetch sessions for this article from the past 24 hours */
    var cutoff = new GlideDateTime();
    cutoff.addDays(-1);

    var gr = new GlideRecord('x_searchpulse_session');
    gr.addQuery('clicked_article', articleSysId);
    gr.addQuery('timestamp', '>=', cutoff.getValue());
    gr.query();

    var delta = 0, pos = 0, neg = 0, total = 0;
    while (gr.next()) {
        var oc = gr.getValue('outcome') || 'B';
        var w  = WEIGHTS.hasOwnProperty(oc) ? WEIGHTS[oc] : 0;
        delta += w;
        if (w > 0) { pos++; } else if (w < 0) { neg++; }
        total++;
    }

    if (total === 0) { return false; }

    /* Upsert reputation record */
    var repGR = new GlideRecord('x_searchpulse_article_reputation');
    repGR.addQuery('article', articleSysId);
    repGR.setLimit(1);
    repGR.query();

    var isNew    = !repGR.next();
    var base     = isNew ? 50 : (parseInt(repGR.getValue('reputation_score'), 10) || 50);
    var newScore = Math.min(100, Math.max(0, base + delta));

    if (isNew) {
        repGR = new GlideRecord('x_searchpulse_article_reputation');
        repGR.initialize();
        repGR.setValue('article',          articleSysId);
        repGR.setValue('positive_signals', pos);
        repGR.setValue('negative_signals', neg);
        repGR.setValue('sessions_count',   total);
    } else {
        repGR.setValue('positive_signals', (parseInt(repGR.getValue('positive_signals'), 10) || 0) + pos);
        repGR.setValue('negative_signals', (parseInt(repGR.getValue('negative_signals'), 10) || 0) + neg);
        repGR.setValue('sessions_count',   (parseInt(repGR.getValue('sessions_count'),   10) || 0) + total);
    }

    repGR.setValue('reputation_score', newScore);
    repGR.setValue('last_calculated',  new GlideDateTime().getValue());

    isNew ? repGR.insert() : repGR.update();

    gs.debug('SearchPulse: article=' + articleSysId + ' base=' + base + ' delta=' + delta + ' new=' + newScore, 'SearchPulse');
    return true;
}

sys_ui_script.script:
/**
 * SearchPulseTracker - UI Script (x_searchpulse scope)
 *
 * Attach to any Service Portal page that shows search results.
 * Usage from a widget client script or AngularJS controller:
 *
 *   SearchPulseTracker.init('expense report');         // on search submit
 *   SearchPulseTracker.summaryFeedback('up');           // thumbs up on AI summary
 *   SearchPulseTracker.summaryFeedback('down');         // thumbs down
 *   SearchPulseTracker.resultClicked('kb_article_id'); // on result link click
 *   SearchPulseTracker.detectReformulation();           // when user changes query
 */
var SearchPulseTracker = (function () {
    'use strict';

    var _sessionId  = null;
    var _lastQuery  = '';
    var _active     = false;
    var _scrollDone = false;

    /* ---- public API ---- */

    /**
     * init(query)
     * Must be called on each search submission.
     * Creates a new session via GlideAjax and wires scroll / unload listeners.
     */
    function init(query) {
        if (!query || query.trim().length < 2) { return; }

        /* If same session is active and query changed, it is a reformulation */
        if (_active && query !== _lastQuery) { detectReformulation(); }

        _sessionId  = _generateId();
        _lastQuery  = query;
        _active     = true;
        _scrollDone = false;

        /* Create server-side session record */
        _ajax('createSession', {
            sysparm_session_id: _sessionId,
            sysparm_query:      query,
            sysparm_user:       _getCurrentUserSysId()
        }, function () {});

        /* Persist for cross-page return detection */
        try {
            sessionStorage.setItem('sp_xsp_sid',   _sessionId);
            sessionStorage.setItem('sp_xsp_query', query);
        } catch (e) {}

        _attachScrollDetection();
        window.addEventListener('beforeunload', _onPageUnload);
    }

    /**
     * summaryFeedback(type)
     * type: 'up' or 'down'
     * Call when user clicks thumbs up / down on the AI summary.
     */
    function summaryFeedback(type) {
        if (!_sessionId) { return; }
        _sendSignal((type === 'up') ? 'summary_up' : 'summary_down', null);
    }

    /**
     * scrollDetection()
     * Fire when the results list scrolls into the viewport.
     * Auto-wired via IntersectionObserver; also exposed for manual trigger.
     */
    function scrollDetection() {
        if (_scrollDone || !_sessionId) { return; }
        _scrollDone = true;
        _sendSignal('scroll', null);
    }

    /**
     * resultClicked(articleSysId)
     * Call on click of any search result link.
     * articleSysId - sys_id of the kb_knowledge article.
     */
    function resultClicked(articleSysId) {
        if (!_sessionId) { return; }
        _sendSignal('click', articleSysId || null);
        /* Mark return detection flag for when user navigates back */
        try {
            sessionStorage.setItem('sp_xsp_return', '1');
            sessionStorage.setItem('sp_xsp_sid',    _sessionId);
        } catch (e) {}
    }

    /**
     * detectReformulation()
     * Call when the user changes the search query mid-session.
     */
    function detectReformulation() {
        if (!_sessionId) { return; }
        _sendSignal('reformulate', null);
    }

    /* ---- private helpers ---- */

    function _attachScrollDetection() {
        var el = document.getElementById('sp-search-results');

        if (el && window.IntersectionObserver) {
            var obs = new IntersectionObserver(function (entries) {
                entries.forEach(function (entry) {
                    if (entry.isIntersecting) { scrollDetection(); obs.disconnect(); }
                });
            }, { threshold: 0.1 });
            obs.observe(el);
            return;
        }

        /* Fallback for browsers without IntersectionObserver */
        window.addEventListener('scroll', function _scrollFallback() {
            if (!_sessionId || _scrollDone) {
                window.removeEventListener('scroll', _scrollFallback);
                return;
            }
            var el2 = document.getElementById('sp-search-results');
            if (el2 && el2.getBoundingClientRect().top < window.innerHeight) {
                window.removeEventListener('scroll', _scrollFallback);
                scrollDetection();
            }
        }, { passive: true });
    }

    function _onPageUnload() {
        try {
            var returnFlag = sessionStorage.getItem('sp_xsp_return');
            if (returnFlag === '1') {
                var prevSid = sessionStorage.getItem('sp_xsp_sid');
                if (prevSid) { _sessionId = prevSid; _sendSignalSync('return'); }
                sessionStorage.removeItem('sp_xsp_return');
            }
        } catch (e) {}
    }

    function _sendSignal(signal, article) {
        var params = { sysparm_session: _sessionId, sysparm_signal: signal };
        if (article) { params.sysparm_article = article; }
        _ajax('captureSignal', params, function () {});
    }

    /* sendBeacon for beforeunload where async XHR may be cancelled */
    function _sendSignalSync(signal) {
        try {
            if (navigator.sendBeacon) {
                var payload = JSON.stringify({ session: _sessionId, signal: signal });
                navigator.sendBeacon('/api/x_searchpulse/signal', new Blob([payload], { type: 'application/json' }));
            }
        } catch (e) { /* best effort */ }
    }

    function _ajax(method, params, callback) {
        var ga = new GlideAjax('x_searchpulse.SearchPulseSignalAPI');
        ga.addParam('sysparm_name', method);
        for (var key in params) {
            if (params.hasOwnProperty(key)) { ga.addParam(key, params[key]); }
        }
        ga.getXML(callback || function () {});
    }

    function _generateId() {
        var arr = new Uint8Array(16);
        if (window.crypto && window.crypto.getRandomValues) {
            window.crypto.getRandomValues(arr);
        } else {
            for (var i = 0; i < 16; i++) { arr[i] = Math.floor(Math.random() * 256); }
        }
        return Array.prototype.map.call(arr, function (b) {
            return ('00' + b.toString(16)).slice(-2);
        }).join('');
    }

    function _getCurrentUserSysId() {
        return (window.NOW && window.NOW.user && window.NOW.user.sys_id) ? window.NOW.user.sys_id : null;
    }

    /* On page load, check if the user has returned from an article */
    (function _checkReturnOnLoad() {
        try {
            if (sessionStorage.getItem('sp_xsp_return') === '1') {
                var prevSid = sessionStorage.getItem('sp_xsp_sid');
                if (prevSid) {
                    _sessionId = prevSid;
                    _sendSignal('return', null);
                }
                sessionStorage.removeItem('sp_xsp_return');
            }
        } catch (e) {}
    }());

    /* Expose public surface */
    return {
        init:                init,
        summaryFeedback:     summaryFeedback,
        scrollDetection:     scrollDetection,
        resultClicked:       resultClicked,
        detectReformulation: detectReformulation,
        getSessionId:        function () { return _sessionId; }
    };
}());

sp_widget.client_script:
function SearchPulseConfidenceCtrl($scope) {
    'use strict';
    var c  = this;
    c.conf = $scope.data.confidence || { score: 50, label: 'Medium', color: 'amber' };
    c.show = !!$scope.data.show;

    c.getIcon = function () {
        var map = { High: 'fa-check-circle', Medium: 'fa-exclamation-circle', Low: 'fa-times-circle' };
        return map[c.conf.label] || 'fa-circle';
    };
    c.barWidth   = function () { return (c.conf.score || 0) + '%'; };
    c.colorClass = function () {
        var map = { green: 'sp-conf-high', amber: 'sp-conf-medium', red: 'sp-conf-low' };
        return map[c.conf.color] || 'sp-conf-medium';
    };
}

sp_widget.script:
(function () {
    'use strict';
    data.show       = false;
    data.confidence = { score: 50, label: 'Medium', color: 'amber' };

    var sessionSysId  = (options && options.session_sys_id)  || '';
    var articleSysIds = (options && options.article_sys_ids) || '';

    var articleList = [];

    if (sessionSysId) {
        var src = new GlideRecord('x_searchpulse_summary_sources');
        src.addQuery('session', sessionSysId);
        src.query();
        while (src.next()) { articleList.push(src.getValue('article')); }
    } else if (articleSysIds) {
        articleList = articleSysIds.split(',').map(function (s) { return s.trim(); }).filter(Boolean);
    }

    try {
        var engine      = new x_searchpulse.SearchPulseConfidence();
        data.confidence = engine.calculateConfidence(articleList);
        data.show       = true;
    } catch (e) {
        gs.logError('SearchPulse Confidence Indicator widget: ' + e.message, 'SearchPulse');
    }
}());

sp_widget.client_script:
function SearchPulseBadgeDisplayCtrl($scope, $sce) {
    'use strict';
    var c          = this;
    c.results      = $scope.data.results   || [];
    c.confidence   = $scope.data.confidence || { label: 'Medium', color: 'amber', score: 50 };
    c.query        = $scope.data.query     || '';
    c.feedbackDone = false;
    c.searched     = !!$scope.data.searched;

    c.colorClass = function (color) {
        return { green: 'sp-badge-green', blue: 'sp-badge-blue', amber: 'sp-badge-amber' }[color] || '';
    };

    c.confClass = function () {
        return { green: 'sp-conf-badge-high', amber: 'sp-conf-badge-medium', red: 'sp-conf-badge-low' }[c.confidence.color] || '';
    };

    c.onResultClick = function (result) {
        if (window.SearchPulseTracker) { SearchPulseTracker.resultClicked(result.sys_id); }
    };

    c.summaryFeedback = function (type) {
        if (c.feedbackDone) { return; }
        c.feedbackDone = type;
        if (window.SearchPulseTracker) { SearchPulseTracker.summaryFeedback(type); }
    };

    c.safeSnippet = function (html) { return $sce.trustAsHtml(html || ''); };
}

