sp_widget.script:
(function () {
    'use strict';

    var query      = (input && input.query) ? input.query.trim() : '';
    var maxResults = (options && options.max_results) ? parseInt(options.max_results, 10) : 10;

    data.results    = [];
    data.confidence = { score: 50, label: 'Medium', color: 'amber' };
    data.query      = query;
    data.searched   = !!query;

    if (!query || query.length < 2) { return; }

    try {
        /* Search KB articles */
        var rawResults  = _searchKB(query, maxResults);
        if (rawResults.length === 0) { data.results = []; return; }

        /* Attach trust badges */
        var sysIds      = rawResults.map(function (r) { return r.sys_id; });
        var badgeEngine = new x_searchpulse.SearchPulseBadgeEngine();
        var badgeMap    = badgeEngine.getBadgesForList(sysIds);

        for (var i = 0; i < rawResults.length; i++) {
            rawResults[i].badge = badgeMap[rawResults[i].sys_id] || { show: false };
        }

        /* Calculate AI summary confidence */
        var confEngine  = new x_searchpulse.SearchPulseConfidence();
        data.confidence = confEngine.calculateConfidence(sysIds);
        data.results    = rawResults;

    } catch (e) {
        gs.logError('SearchPulse Trust Badge Display: ' + e.message, 'SearchPulse');
        data.results = [];
    }

    function _searchKB(q, limit) {
        var results = [];
        var gr      = new GlideRecord('kb_knowledge');
        gr.addActiveQuery();
        gr.addQuery('workflow_state', 'published');
        var qc = gr.addQuery('short_description', 'CONTAINS', q);
        qc.addOrCondition('text', 'CONTAINS', q);
        gr.setLimit(limit);
        gr.orderByDesc('sys_updated_on');
        gr.query();

        while (gr.next()) {
            results.push({
                sys_id:   gr.getUniqueValue(),
                title:    gr.getDisplayValue('short_description'),
                snippet:  _snippet(gr.getValue('text'), q),
                url:      '/kb_view.do?sysparm_article=' + gr.getValue('number'),
                category: gr.getDisplayValue('kb_category'),
                updated:  _relDate(gr.getValue('sys_updated_on'))
            });
        }
        return results;
    }

    function _snippet(text, q) {
        if (!text) { return ''; }
        var plain = text.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
        var idx   = plain.toLowerCase().indexOf(q.toLowerCase());
        if (idx === -1) { return plain.substring(0, 160) + (plain.length > 160 ? '...' : ''); }
        var s = Math.max(0, idx - 60), e = Math.min(plain.length, idx + q.length + 100);
        return (s > 0 ? '...' : '') + plain.substring(s, e) + (e < plain.length ? '...' : '');
    }

    function _relDate(v) {
        if (!v) { return ''; }
        var d = Math.abs(Math.floor(GlideDateTime.subtract(new GlideDateTime(v), new GlideDateTime()).getDayPart()));
        if (d === 0) { return 'today'; }
        if (d === 1) { return 'yesterday'; }
        if (d <= 30)  { return d + ' days ago'; }
        if (d <= 365) { return Math.floor(d / 30) + ' months ago'; }
        return Math.floor(d / 365) + ' years ago';
    }
}());

sys_script.script:
(function executeRule(current, previous) {

    var articleSysId = current.getValue('article');
    if (!articleSysId) { return; }

    /* Look up the KB article */
    var articleGR = new GlideRecord('kb_knowledge');
    if (!articleGR.get(articleSysId)) { return; }

    var articleTitle  = articleGR.getDisplayValue('short_description');
    var articleNumber = articleGR.getValue('number');
    var ownerId       = articleGR.getValue('author');
    var newScore      = parseInt(current.getValue('reputation_score'), 10);

    gs.log('SearchPulse Content Quality Monitor: article ' + articleNumber +
           ' (' + articleTitle + ') dropped to score ' + newScore + '. Creating improvement task.', 'SearchPulse');

    /* Action 1: Create a task for the Knowledge Owner */
    var taskGR = new GlideRecord('kb_task');
    if (!taskGR.isValid()) {
        /* Fallback to incident task if kb_task not available */
        taskGR = new GlideRecord('task');
    }
    taskGR.initialize();
    taskGR.setValue('short_description',
        '[SearchPulse] Article needs review: ' + articleTitle);
    taskGR.setValue('description',
        'SearchPulse has detected that KB article ' + articleNumber + ' (' + articleTitle + ') ' +
        'has a reputation score of ' + newScore + '/100, which is below the quality threshold of 40.\n\n' +
        'Users are signalling low satisfaction when searching for this content.\n\n' +
        'Recommended actions:\n' +
        '1. Review article content for accuracy and completeness\n' +
        '2. Update outdated procedures or screenshots\n' +
        '3. Improve clarity and structure\n' +
        '4. Verify article addresses common user queries\n\n' +
        'Article link: /kb_view.do?sysparm_article=' + articleNumber);
    taskGR.setValue('priority', 2);
    if (ownerId) { taskGR.setValue('assigned_to', ownerId); }
    var taskSysId = taskGR.insert();
    gs.log('SearchPulse: created task ' + taskSysId + ' for article ' + articleNumber, 'SearchPulse');

    /* Action 2: Notify content owner via email notification event */
    if (ownerId) {
        gs.eventQueue('x_searchpulse.low_reputation_alert', current, ownerId, articleTitle);
    }

    /* Action 3: Log article update suggestion */
    gs.log('SearchPulse Content Quality Monitor: suggest updating article ' +
           articleNumber + ' - current score=' + newScore + '/100', 'SearchPulse');

})(current, previous);
